// accountDetailLabel returns a human-readable "Root > Detail" label.
func accountDetailLabel(rootType, detailType string) string {
	root := rootTypeLabel(rootType)
	detail := detailTypeLabel(detailType)
	if detail == "" {
		return root
	}
	return root + " > " + detail
}

func rootTypeLabel(s string) string {
	switch s {
	case "asset":
		return "Asset"
	case "liability":
		return "Liability"
	case "equity":
		return "Equity"
	case "revenue":
		return "Revenue"
	case "expense":
		return "Expense"
	case "cost_of_sales":
		return "Cost of Sales"
	default:
		return s
	}
}

func detailTypeLabel(s string) string {
	switch s {
	case "sales_tax_payable":
		return "Sales Tax on Sales and Purchases"
	case "accounts_receivable":
		return "Accounts Receivable"
	case "accounts_payable":
		return "Accounts Payable"
	case "bank":
		return "Bank"
	case "other_current_asset":
		return "Other Current Asset"
	case "other_current_liability":
		return "Other Current Liability"
	case "credit_card":
		return "Credit Card"
	default:
		return ""
	}
}

